def perceive(data):
    text = data if isinstance(data, str) else str(data)
    client = ""
    adverse = []
    for line in text.splitlines():
        if ":" not in line:
            continue
        key, _, value = line.partition(":")
        key = key.strip().lower()
        value = value.strip()
        if key in ("client", "prospective client", "matter"):
            client = value
        elif key in ("adverse", "adverse parties", "against", "opposing"):
            parts = value.replace(";", ",").split(",")
            adverse = [p.strip() for p in parts if p.strip()]
    return {"matter": {"client": client, "adverse_parties": adverse,
                       "intake_complete": False}}

